var f = this, id = f.get_id(), g = f.getItem('hrdmpcct')._controlBehavior;
var v = this._language == 'v', d = g._getColumnOrder('ngay_hl_tu');
var e = (v ? 'Hiệu lực từ ngày đã có trong phần thông tin chi tiết, không thể lưu được.' : 'Invalid effective date from, it already exists.');

if (f._checked) {
  var a = query$Select(g, 'count$1 $groupBy ngay_hl_tu');
  for (var i = 0; i < a.length; i++) {
    if (a[i][1] > 1) {
      f._checked = false;
      $func.hideWait(id);      
      $message.show(e, String.format('$find(\'{0}\').focus(\'hrdmpcct\');$find(\'{1}\')._focusWhenTabChanged()', id, g.get_id()));      
      break;
    }
  }
}

script.text:
      &OutlineEntry;

function active$Allowance(f) {
  f.add_onResponseComplete(on$Allowance$ResponseComplete);
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  changeLookupReadonly(f, 'ds_ma_cong', true);
  onChange$AllowanceList$Nature(f);
}
function close$Allowance(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Allowance$ResponseComplete)} catch (ex) {}
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('hrdmpcct')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    default:
      break;
  }
}
function on$Allowance$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_pc');
      break;
    default:
      break;
  }
}
function onChange$Nature(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {    
    case 'tinh_chat':
      onChange$AllowanceList$Nature(f, true);
      break;
    default:
      break;
  }
}
function onChange$AllowanceList$Nature(f, force) {window.setTimeout(String.format('onFocus$AllowanceList$Nature(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$AllowanceList$Nature(id, force) {
  var f = $find(id), v = (f.getItem('tinh_chat').value == 1), t1 = f.getItem('ty_le'), t2 = f.getItem('ds_ma_cong');;
  setFieldsEmpty(f, 'ds_ma_cong', v);
  if (force) setItemLive(t1, t2, !v);
  setItemDisable(f, 'ds_ma_cong', !v);
}
function setItemLive(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus(); t1.live = true;}}
    else {if (t1.live) {t2.disabled = false; t2.focus(); t2.live = true;}}
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
function onChange$Voucher$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['ma_pc', 'hrdmpcct', 'stt']);}

